<?php require_once 'mailer.php'; verify_csrf(); if($_SERVER['REQUEST_METHOD']==='POST'){ $email=filter_var($_POST['email']??'',FILTER_VALIDATE_EMAIL); $s=pdo()->prepare('SELECT * FROM users WHERE email=?'); $s->execute([$email]); if($u=$s->fetch()){ $token=bin2hex(random_bytes(32)); $otp=(string)random_int(100000,999999); pdo()->prepare('INSERT INTO password_resets(user_id,token,otp,expires_at) VALUES(?,?,?,DATE_ADD(NOW(),INTERVAL 30 MINUTE))')->execute([$u['id'],$token,$otp]); email_password_reset($u,$token,$otp); } flash('If this email exists, a reset link and OTP were sent.'); } app_header('Forgot Password'); ?><form class="auth card" method="post"><h1>Forgot Password</h1><?=csrf_field()?><input type="email" name="email" placeholder="Registered email" required><button class="btn">Send reset</button></form><?php app_footer(); ?>
